// ==================== Wwise 风格音效系统 ====================

// 混响效果器（模拟 Wwise 混响）
function createReverb() {
    const ctx = gameState.audioContext;
    const convolver = ctx.createConvolver();

    // 创建脉冲响应缓冲区
    const rate = ctx.sampleRate;
    const length = rate * 2.0; // 2秒混响
    const decay = 2.0;
    const impulse = ctx.createBuffer(2, length, rate);

    for (let channel = 0; channel < 2; channel++) {
        const channelData = impulse.getChannelData(channel);
        for (let i = 0; i < length; i++) {
            // 指数衰减 + 随机噪声 = 混响效果
            channelData[i] = (Math.random() * 2 - 1) * Math.pow(1 - i / length, decay);
        }
    }

    convolver.buffer = impulse;
    return convolver;
}

let reverbNode = null;
let masterGain = null;

// 初始化主混音器
function initMasterMixer() {
    if (!gameState.audioContext) return;

    if (!reverbNode) {
        reverbNode = createReverb();
        reverbNode.connect(gameState.audioContext.destination);
    }

    if (!masterGain) {
        masterGain = gameState.audioContext.createGain();
        masterGain.gain.value = 0.8;
        masterGain.connect(gameState.audioContext.destination);
    }
}

// Stinger 音效 - 选择声部
function playSelectStinger() {
    initAudioContext();
    const ctx = gameState.audioContext;
    const now = ctx.currentTime;

    // 清脆的提示音
    playTone(880, 0.1, now, 0.2, 'sine');
    playTone(1100, 0.08, now + 0.05, 0.15, 'sine');
}

// Stinger 音效 - 正确
function playCorrectStinger() {
    initAudioContext();
    const ctx = gameState.audioContext;
    const now = ctx.currentTime;

    // 成功音效 - 上升音阶
    playTone(523.25, 0.15, now, 0.3, 'sine'); // C5
    playTone(659.25, 0.15, now + 0.1, 0.3, 'sine'); // E5
    playTone(783.99, 0.2, now + 0.2, 0.35, 'sine'); // G5
    playTone(1046.50, 0.4, now + 0.35, 0.4, 'sine'); // C6
}

// Stinger 音效 - 错误
function playWrongStinger() {
    initAudioContext();
    const ctx = gameState.audioContext;
    const now = ctx.currentTime;

    // 错误音效 - 下降音阶
    playTone(392.00, 0.15, now, 0.3, 'triangle'); // G4
    playTone(349.23, 0.15, now + 0.1, 0.3, 'triangle'); // F4
    playTone(329.63, 0.2, now + 0.2, 0.35, 'triangle'); // E4
    playTone(261.63, 0.3, now + 0.35, 0.4, 'triangle'); // C4
}

// 阶段切换音效
function playPhaseTransitionStinger(phase) {
    initAudioContext();
    const ctx = gameState.audioContext;
    const now = ctx.currentTime;

    if (phase === 2) {
        // 进入选择阶段
        playTone(440, 0.1, now, 0.25, 'sine');
        playTone(554, 0.1, now + 0.1, 0.25, 'sine');
        playTone(659, 0.15, now + 0.2, 0.3, 'sine');
    } else if (phase === 3) {
        // 进入验证阶段
        playTone(392, 0.1, now, 0.25, 'sine');
        playTone(523, 0.1, now + 0.1, 0.25, 'sine');
        playTone(659, 0.1, now + 0.2, 0.25, 'sine');
        playTone(784, 0.2, now + 0.3, 0.3, 'sine');
    }
}

// 带淡入淡出的播放（Wwise 风格）
function playToneWithFade(frequency, duration, startTime, volume = 0.3, type = 'sine', attack = 0.05, release = 0.1) {
    const ctx = gameState.audioContext;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.type = type;
    osc.frequency.value = frequency;

    // ADSR 包络
    gain.gain.setValueAtTime(0, startTime);
    gain.gain.linearRampToValueAtTime(volume, startTime + attack);
    gain.gain.setValueAtTime(volume, startTime + duration - release);
    gain.gain.exponentialRampToValueAtTime(0.001, startTime + duration);

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start(startTime);
    osc.stop(startTime + duration);

    return { osc, gain };
}

// 改进的鼓声合成（更有力的打击感）
function playDrumSoundEnhanced(type, startTime, velocity = 1.0) {
    const ctx = gameState.audioContext;

    if (type === 'kick') {
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();

        osc.frequency.setValueAtTime(150, startTime);
        osc.frequency.exponentialRampToValueAtTime(40, startTime + 0.1);

        gain.gain.setValueAtTime(0.8 * velocity, startTime);
        gain.gain.exponentialRampToValueAtTime(0.001, startTime + 0.5);

        osc.connect(gain);
        gain.connect(ctx.destination);

        osc.start(startTime);
        osc.stop(startTime + 0.5);

        // 添加低频增强
        const subOsc = ctx.createOscillator();
