        // 播放片段（节拍对齐版本）
        function playPart(part, variant, loop = true, duration = 4000) {
            initAudioContext();
            initBeatScheduler();

            const ctx = gameState.audioContext;
            const beatDur = 0.5;

            function playBeat(startTime) {
                if (part === 'drums') {
                    const pattern = generateDrumsPattern(variant);
                    pattern.forEach((drum, i) => {
                        if (drum) playDrumSound(drum, startTime + i * beatDur);
                    });
                } else if (part === 'bass') {
                    const pattern = generateBassPattern(variant);
                    pattern.forEach((note, i) => {
                        if (note) playTone(noteFrequencies[note], beatDur * 0.9, startTime + i * beatDur, 0.4, 'triangle');
                    });
                } else if (part === 'melody') {
                    const pattern = generateMelodyPattern(variant);
                    pattern.forEach((note, i) => {
                        if (note) playTone(noteFrequencies[note], beatDur * 0.8, startTime + i * beatDur, 0.25, 'sine');
                    });
                } else if (part === 'harmony') {
                    const pattern = generateHarmonyPattern(variant);
                    pattern.forEach((chord, i) => {
                        if (chord) {
                            chord.forEach(note => {
                                playTone(noteFrequencies[note], beatDur * 1.2, startTime + i * beatDur, 0.15, 'sine');
                            });
                        }
                    });
                }
            }

            // 等待下一个节拍点再开始播放
            const nextBeat = getNextBeatTime();
            const waitTime = (nextBeat - ctx.currentTime) * 1000;

            // 显示等待提示（可选）
            console.log(`Waiting ${waitTime.toFixed(0)}ms for next beat...`);

            setTimeout(() => {
                playBeat(ctx.currentTime);

                if (loop) {
                    const loopInterval = setInterval(() => {
                        playBeat(ctx.currentTime);
                    }, duration);
                    gameState.loopIntervals.push(loopInterval);
                    return loopInterval;
                }
            }, Math.max(0, waitTime));
        }

        // 播放目标组合（循环）
        function playTargetCombination(loop = true) {
            initAudioContext();
            clearAllLoops();

            parts.forEach(part => {
                playPart(part, gameState.targetCombination[part], loop);
            });
        }

        // 播放用户选择
        function playUserSelection(loop = true) {
            initAudioContext();
            clearAllLoops();

            parts.forEach(part => {
                if (gameState.userSelection[part]) {
                    playPart(part, gameState.userSelection[part], loop);
                }
            });
        }

