// 播放片段（节拍对齐版本 + Wwise 风格混音）
function playPart(part, variant, loop = true, duration = 4000) {
    initAudioContext();
    initMasterMixer();
    initBeatScheduler();

    const ctx = gameState.audioContext;
    const beatDur = 0.5;
    const baseVolume = partVolumes[part] || 0.3;

    function playBeat(startTime) {
        if (part === 'drums') {
            const pattern = generateDrumsPattern(variant);
            pattern.forEach((drum, i) => {
                if (drum) playDrumSoundEnhanced(drum, startTime + i * beatDur, baseVolume / 0.4);
            });
        } else if (part === 'bass') {
            const pattern = generateBassPattern(variant);
            pattern.forEach((note, i) => {
                if (note) playToneWithFade(noteFrequencies[note], beatDur * 0.9, startTime + i * beatDur, baseVolume, 'triangle', 0.02, 0.1);
            });
        } else if (part === 'melody') {
            const pattern = generateMelodyPattern(variant);
            pattern.forEach((note, i) => {
                if (note) playToneWithFade(noteFrequencies[note], beatDur * 0.8, startTime + i * beatDur, baseVolume, 'sine', 0.05, 0.1);
            });
        } else if (part === 'harmony') {
            const pattern = generateHarmonyPattern(variant);
            pattern.forEach((chord, i) => {
                if (chord) {
                    chord.forEach(note => {
                        playToneWithFade(noteFrequencies[note], beatDur * 1.2, startTime + i * beatDur, baseVolume * 0.8, 'sine', 0.1, 0.15);
                    });
                }
            });
        }
    }

    // 等待下一个节拍点再开始播放
    const nextBeat = getNextBeatTime();
    const waitTime = (nextBeat - ctx.currentTime) * 1000;

    setTimeout(() => {
        playBeat(ctx.currentTime);

        if (loop) {
            const loopInterval = setInterval(() => {
                playBeat(ctx.currentTime);
            }, duration);
            gameState.loopIntervals.push(loopInterval);
            return loopInterval;
        }
    }, Math.max(0, waitTime));
}

