// ==================== Wwise 风格交互音乐系统 ====================

// Wwise Switch 状态定义
const SWITCH_STATES = {
    NONE: 'none',
    A: 'A',
    B: 'B', 
    C: 'C'
};

// Music Track 定义 (4个轨道)
const MUSIC_TRACKS = {
    melody: { name: 'Melody', volume: 0.25, currentState: SWITCH_STATES.NONE },
    harmony: { name: 'Harmony', volume: 0.15, currentState: SWITCH_STATES.NONE },
    bass: { name: 'Bass', volume: 0.35, currentState: SWITCH_STATES.NONE },
    drums: { name: 'Drums', volume: 0.40, currentState: SWITCH_STATES.NONE }
};

// 活跃的音乐实例 (Voice Limiting - 每个轨道限制为1)
const activeMusicVoices = {
    melody: null,
    harmony: null,
    bass: null,
    drums: null
};

// 主混音器 (Master Mixer)
let masterGainNode = null;
let trackGainNodes = {};

function initMasterMixer() {
    if (!gameState.audioContext) return;

    if (!masterGainNode) {
        masterGainNode = gameState.audioContext.createGain();
        masterGainNode.gain.value = 0.8;
        masterGainNode.connect(gameState.audioContext.destination);
    }

    // 为每个 Music Track 创建 Gain Node (垂直混音控制)
    parts.forEach(part => {
        if (!trackGainNodes[part]) {
            trackGainNodes[part] = gameState.audioContext.createGain();
            trackGainNodes[part].gain.value = MUSIC_TRACKS[part].volume;
            trackGainNodes[part].connect(masterGainNode);
        }
    });
}

// Wwise SetSwitch - 切换 Music Track 状态
function setSwitch(part, state) {
    initAudioContext();
    initMasterMixer();

    // 更新 Switch 状态
    MUSIC_TRACKS[part].currentState = state;

    // 实例限制：立即停止该轨道的旧实例 (Voice Limiting = 1)
    if (activeMusicVoices[part]) {
        stopMusicVoice(part);
    }

    // 如果状态不是 NONE，开始新实例
    if (state !== SWITCH_STATES.NONE) {
        // 等待下一个乐句边界开始 (节拍同步)
        const nextPhraseTime = getNextPhraseTime();
        const waitTime = Math.max(0, (nextPhraseTime - gameState.audioContext.currentTime) * 1000);

        setTimeout(() => {
            startMusicVoice(part, state, nextPhraseTime);
        }, waitTime);
    }
}

// 停止音乐实例 (立即打断)
function stopMusicVoice(part) {
    const voice = activeMusicVoices[part];
    if (voice) {
        // 立即停止所有振荡器和增益节点
        voice.oscillators.forEach(osc => {
            try {
                osc.stop();
                osc.disconnect();
            } catch(e) {}
        });
        voice.gains.forEach(g => {
            try {
                g.disconnect();
            } catch(e) {}
        });

        // 清除循环
        if (voice.intervalId) {
            clearInterval(voice.intervalId);
        }

        activeMusicVoices[part] = null;
    }
}

// 开始音乐实例
function startMusicVoice(part, state, startTime) {
    const ctx = gameState.audioContext;
    const beatDur = 0.5; // 120 BPM
    const trackGain = trackGainNodes[part];

    const voice = {
        part: part,
        state: state,
        oscillators: [],
        gains: [],
        intervalId: null
    };

    function playPhrase(phraseStartTime) {
        if (!activeMusicVoices[part] || activeMusicVoices[part].state !== state) {
            return; // 状态已改变，不再播放
        }

        if (part === 'drums') {
            const pattern = generateDrumsPattern(state);
            pattern.forEach((drum, i) => {
                if (drum) {
                    const { osc, gain } = createDrumSource(drum, phraseStartTime + i * beatDur, MUSIC_TRACKS[part].volume);
                    if (osc) {
                        voice.oscillators.push(osc);
                        voice.gains.push(gain);
                    }
                }
            });
        } else if (part === 'bass') {
            const pattern = generateBassPattern(state);
            pattern.forEach((note, i) => {
                if (note) {
                    const { osc, gain } = createNoteSource(noteFrequencies[note], beatDur * 0.9, phraseStartTime + i * beatDur, MUSIC_TRACKS[part].volume, 'triangle');
                    voice.oscillators.push(osc);
                    voice.gains.push(gain);
                }
            });
        } else if (part === 'melody') {
            const pattern = generateMelodyPattern(state);
            pattern.forEach((note, i) => {
                if (note) {
                    const { osc, gain } = createNoteSource(noteFrequencies[note], beatDur * 0.8, phraseStartTime + i * beatDur, MUSIC_TRACKS[part].volume, 'sine');
                    voice.oscillators.push(osc);
                    voice.gains.push(gain);
                }
            });
        } else if (part === 'harmony') {
            const pattern = generateHarmonyPattern(state);
            pattern.forEach((chord, i) => {
                if (chord) {
                    chord.forEach(note => {
                        const { osc, gain } = createNoteSource(noteFrequencies[note], beatDur * 1.2, phraseStartTime + i * beatDur, MUSIC_TRACKS[part].volume * 0.8, 'sine');
                        voice.oscillators.push(osc);
                        voice.gains.push(gain);
                    });
                }
            });
        }
    }

    // 立即播放第一遍
    playPhrase(startTime);

    // 设置循环 (每4秒 = 8拍 = 1个乐句)
    voice.intervalId = setInterval(() => {
        const now = ctx.currentTime;
        const nextPhrase = Math.ceil(now / 4) * 4;
        playPhrase(nextPhrase);
    }, 4000);

    activeMusicVoices[part] = voice;
}

// 创建音符音频源
function createNoteSource(frequency, duration, startTime, volume, type) {
    const ctx = gameState.audioContext;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.type = type;
    osc.frequency.value = frequency;

    // ADSR 包络
    gain.gain.setValueAtTime(0, startTime);
    gain.gain.linearRampToValueAtTime(volume, startTime + 0.02);
    gain.gain.setValueAtTime(volume, startTime + duration - 0.05);
    gain.gain.exponentialRampToValueAtTime(0.001, startTime + duration);

    osc.connect(gain);
    gain.connect(masterGainNode);

    osc.start(startTime);
    osc.stop(startTime + duration);

    return { osc, gain };
}

// 创建鼓声音频源
function createDrumSource(type, startTime, volume) {
    const ctx = gameState.audioContext;

    if (type === 'kick') {
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();
        osc.frequency.setValueAtTime(150, startTime);
        osc.frequency.exponentialRampToValueAtTime(40, startTime + 0.1);
        gain.gain.setValueAtTime(volume, startTime);
        gain.gain.exponentialRampToValueAtTime(0.001, startTime + 0.5);
        osc.connect(gain);
        gain.connect(masterGainNode);
        osc.start(startTime);
        osc.stop(startTime + 0.5);
        return { osc, gain };
    } else if (type === 'snare') {
        const noise = ctx.createBufferSource();
        const buffer = ctx.createBuffer(1, ctx.sampleRate * 0.2, ctx.sampleRate);
        const data = buffer.getChannelData(0);
        for (let i = 0; i < data.length; i++) data[i] = Math.random() * 2 - 1;
        noise.buffer = buffer;
        const gain = ctx.createGain();
        gain.gain.setValueAtTime(volume * 0.5, startTime);
        gain.gain.exponentialRampToValueAtTime(0.001, startTime + 0.2);
        noise.connect(gain);
        gain.connect(masterGainNode);
        noise.start(startTime);
        return { osc: noise, gain };
    } else if (type === 'hihat') {
        const noise = ctx.createBufferSource();
        const buffer = ctx.createBuffer(1, ctx.sampleRate * 0.05, ctx.sampleRate);
        const data = buffer.getChannelData(0);
        for (let i = 0; i < data.length; i++) data[i] = Math.random() * 2 - 1;
        noise.buffer = buffer;
        const filter = ctx.createBiquadFilter();
        filter.type = 'highpass';
        filter.frequency.value = 10000;
        const gain = ctx.createGain();
        gain.gain.setValueAtTime(volume * 0.3, startTime);
        gain.gain.exponentialRampToValueAtTime(0.001, startTime + 0.05);
        noise.connect(filter);
        filter.connect(gain);
        gain.connect(masterGainNode);
        noise.start(startTime);
        return { osc: noise, gain };
    }
    return { osc: null, gain: null };
}

// 获取下一个乐句开始时间 (4秒 = 8拍)
function getNextPhraseTime() {
    const ctx = gameState.audioContext;
    const phraseDuration = 4; // 4秒一个乐句
    const currentTime = ctx.currentTime;
    return Math.ceil(currentTime / phraseDuration) * phraseDuration;
}

// 停止所有音乐
function stopAllMusic() {
    parts.forEach(part => stopMusicVoice(part));
}

// ==================== Stinger 音效系统 ====================

// Stinger 音效 - 选择声部
