// Wwise SetSwitch 风格选择 - 垂直叠层 + 实例限制
function selectOption(part, option) {
    initAudioContext();
    initMasterMixer();

    // 播放选择音效
    playSelectStinger();

    // 更新选择状态
    gameState.userSelection[part] = option;

    // 更新UI
    const optionsContainer = document.getElementById(part + 'Options');
    optionsContainer.querySelectorAll('.part-option').forEach(opt => {
        opt.classList.remove('selected');
    });

    const selectedOption = optionsContainer.querySelector(`[data-option="${option}"]`);
    selectedOption.classList.add('selected');

    // 更新状态标签
    document.getElementById(part + 'Status').textContent = option + ' ✓';
    document.getElementById(part + 'Section').classList.add('active');

    // 更新摘要
    document.getElementById('summary' + part.charAt(0).toUpperCase() + part.slice(1)).textContent = 
        option + ' ✓';
    document.getElementById('summary' + part.charAt(0).toUpperCase() + part.slice(1)).classList.add('selected');

    // 更新混音器显示
    updateMixerDisplay();

    // === Wwise 风格：SetSwitch 切换 ===
    // 该轨道实例限制为1，新选择立即打断旧实例
    // 在乐句边界同步切换（垂直叠层）
    setSwitch(part, option);
}

