function playTargetPreview() {
    initAudioContext();

    // 停止当前用户选择
    stopAllMusic();

    // 播放目标组合
    playTargetCombination(true);

    // 显示提示
    const btn = event.target;
    const originalText = btn.innerHTML;
    btn.innerHTML = '🔊 正在播放原曲...';
    btn.disabled = true;

    // 3秒后恢复
    setTimeout(() => {
        btn.innerHTML = originalText;
        btn.disabled = false;

        // 如果用户已经有选择，切回用户的选择
        const hasSelection = parts.some(p => gameState.userSelection[p]);
        if (hasSelection) {
            stopAllMusic();
            parts.forEach(p => {
                if (gameState.userSelection[p]) {
                    setSwitch(p, gameState.userSelection[p]);
                }
            });
        }
    }, 3000);
}

