    gap: 10px;
    margin-bottom: 15px;
    padding-bottom: 10px;
    border-bottom: 1px solid rgba(255,255,255,0.1);
}

.part-icon {
    font-size: 1.8rem;
}

.part-name {
    font-size: 1.1rem;
    font-weight: 600;
}

